## Script for Postgres DB 

-- Optional: generate UUIDs if you want UUID-based ids
CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE IF NOT EXISTS agent_memory (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    session_id VARCHAR(255) NOT NULL,
    message JSONB NOT NULL
);

-- Optional index for faster lookup by session
CREATE INDEX IF NOT EXISTS idx_agent_memory_session_id
    ON agent_memory (session_id);

-- Optional index for JSONB searches
CREATE INDEX IF NOT EXISTS idx_agent_memory_message_gin
    ON agent_memory
    USING GIN (message);
